{
  "version": "arkpilot-a2ui/v2",
  "kind": "behavior-contract",
  "uiTreePath": ".arkpilot/designs/ui-tree.json",
  "appName": "Pinankou 平安扣",
  "summary": "Local-first EHS safety companion. Headless logic: CRUD + status workflow for issues, patrol checkpoint clock-in, emergency contacts, and a derived statistics board. Persisted locally via preferences-backed store, exposed reactively through AppStorage. No backend.",
  "dataModel": {
    "enums": {
      "IssueStatus": ["pending", "inProgress", "resolved", "closed"],
      "IssueSeverity": ["low", "medium", "high", "critical"],
      "IssueCategory": ["fire", "electrical", "mechanical", "environment", "behavior", "other"],
      "ContactPriority": ["primary", "secondary", "backup"],
      "CheckpointStatus": ["pending", "checked"]
    },
    "entities": {
      "Issue": {
        "fields": {
          "id": "string",
          "title": "string",
          "description": "string",
          "location": "string",
          "category": "IssueCategory",
          "severity": "IssueSeverity",
          "status": "IssueStatus",
          "assignee": "string",
          "dueDate": "number (ms timestamp, 0 = none)",
          "photoUri": "string (empty = placeholder)",
          "createdAt": "number (ms)",
          "updatedAt": "number (ms)",
          "notes": "IssueNote[]"
        },
        "derived": {
          "isOverdue": "dueDate>0 && dueDate<now && status not in [resolved,closed]"
        }
      },
      "IssueNote": { "fields": { "id": "string", "text": "string", "createdAt": "number (ms)" } },
      "PatrolCheckpoint": {
        "fields": {
          "id": "string",
          "name": "string",
          "location": "string",
          "status": "CheckpointStatus",
          "note": "string",
          "checkedAt": "number (ms, 0 = not checked)",
          "dayKey": "string (YYYY-MM-DD of the patrol day)"
        }
      },
      "Contact": {
        "fields": {
          "id": "string",
          "name": "string",
          "role": "string",
          "phone": "string",
          "priority": "ContactPriority",
          "createdAt": "number (ms)"
        }
      },
      "ActivityItem": {
        "fields": { "id": "string", "kind": "issue-created|issue-status|patrol-check|contact-added", "title": "string", "subtitle": "string", "createdAt": "number (ms)" },
        "note": "Derived from issues/checkpoints/contacts, sorted desc by createdAt"
      }
    },
    "formState": {
      "issueForm": "title, category, severity, location, assignee, dueDate, description, photoUri, editingIssueId",
      "contactForm": "name, role, phone, priority, editingContactId"
    },
    "computedState": {
      "summary": "openIssues (status in pending|inProgress), overdue (isOverdue), todayPatrol (checkpoints checked today)",
      "stats": "openCount, resolvedCount, overdueCount, severityDistribution, weeklyTrend (last 7 days created counts), overdueItems"
    }
  },
  "services": [
    {
      "name": "LocalStore",
      "kind": "persistence",
      "impl": "@ohos.data.preferences-backed JSON arrays; loaded into AppStorage keys on init and re-persisted on mutation",
      "keys": ["pinankou_issues", "pinankou_checkpoints", "pinankou_contacts"],
      "reactiveAppStorageKeys": ["issues", "checkpoints", "contacts"]
    },
    {
      "name": "PhoneAdapter",
      "kind": "system-action",
      "impl": "call.contact via @kit.AbilityKit want action ohos.want.action.callData / fallback prompt; degrade gracefully",
      "events": ["call-contact"]
    },
    {
      "name": "PhotoAdapter",
      "kind": "optional-input",
      "impl": "camera/file picker optional; defaults to empty placeholder photoUri when unavailable or denied",
      "events": ["attach-photo"]
    },
    {
      "name": "ClockProvider",
      "kind": "helper",
      "impl": "now() ms timestamp + today dayKey (YYYY-MM-DD)",
      "note": "No Date.now in workflow scripts; ArkTS runtime Date is allowed."
    }
  ],
  "stateMachine": {
    "IssueWorkflow": {
      "states": ["pending", "inProgress", "resolved", "closed"],
      "transitions": [
        { "from": "pending", "to": "inProgress", "event": "set-in-progress" },
        { "from": "inProgress", "to": "resolved", "event": "set-resolved" },
        { "from": "resolved", "to": "closed", "event": "set-closed" },
        { "from": "inProgress", "to": "pending", "event": "set-pending" },
        { "from": "resolved", "to": "inProgress", "event": "set-in-progress" },
        { "from": "closed", "to": "inProgress", "event": "reopen" }
      ],
      "sideEffects": ["update updatedAt", "append ActivityItem on transition"]
    },
    "PatrolSession": {
      "states": ["idle", "active"],
      "transitions": [
        { "from": "idle", "to": "active", "event": "start-patrol" },
        { "from": "active", "to": "idle", "event": "all-checked-or-manual-stop" }
      ],
      "checkpointTransitions": [
        { "from": "pending", "to": "checked", "event": "check-checkpoint", "sideEffects": ["set checkedAt=now", "set dayKey=today", "append ActivityItem"] },
        { "from": "checked", "to": "pending", "event": "uncheck-checkpoint", "sideEffects": ["clear checkedAt", "clear note optional"] }
      ]
    }
  },
  "interactionFlows": [
    {
      "flow": "create-issue",
      "trigger": "navigate-to-issue-form (from home/issues)",
      "steps": [
        "open IssueForm with editingIssueId=null",
        "bind inputs to /issueForm/*",
        "on save-issue: validate title non-empty; severity/category defaults applied",
        "persist new Issue status=pending, createdAt=now",
        "append ActivityItem(issue-created)",
        "navigate-back to originating tab; list reflects new item"
      ],
      "errorPath": "title empty -> issue-form-error-message visible, no navigation"
    },
    {
      "flow": "edit-issue-and-workflow",
      "trigger": "issue list tap -> issue-detail",
      "steps": [
        "load /issue/* by id",
        "status-actions set IssueWorkflow transition",
        "add-progress-note appends IssueNote",
        "delete-issue confirms then removes + navigate-back"
      ]
    },
    {
      "flow": "patrol-clock-in",
      "trigger": "start-patrol / tap checkpoint",
      "steps": [
        "start-patrol sets session active, reveals checkpoint list",
        "tap patrol-checkpoint -> patrol-checkpoint screen",
        "check-checkpoint sets checkedAt=now + dayKey=today",
        "patrol-progress-count shows checked/total"
      ]
    },
    {
      "flow": "contact-call",
      "trigger": "contacts-call-button-{id}",
      "steps": ["invoke PhoneAdapter.call(phone)", "graceful fallback if unavailable"]
    },
    {
      "flow": "dashboard-glance",
      "trigger": "home/stats tab",
      "steps": ["compute summary from issues+checkpoints", "render counts, severity chart, overdue list, recent activity", "empty states when no data"]
    }
  ],
  "testTargets": [
    "home-add-issue-button",
    "home-start-patrol-button",
    "home-open-issues-count",
    "home-overdue-count",
    "home-recent-activity-list",
    "issues-add-button",
    "issues-search-input",
    "issues-list",
    "issue-form-title-input",
    "issue-form-severity-segmented",
    "issue-form-save-button",
    "patrol-checkpoint-list",
    "patrol-checkpoint-check-button",
    "contacts-add-button",
    "contacts-call-button-{id}",
    "stats-open-count",
    "stats-severity-chart",
    "stats-overdue-list"
  ],
  "navigation": {
