// Domain enums for the Pinankou safety app.
// Shared by models, services, controllers, and UI. Keep names stable for serialization.

export type IssueStatus = 'pending' | 'inProgress' | 'resolved' | 'closed';

export type IssueSeverity = 'low' | 'medium' | 'high' | 'critical';

export type IssueCategory = 'fire' | 'electrical' | 'mechanical' | 'environment' | 'behavior' | 'other';

export type ContactPriority = 'primary' | 'secondary' | 'backup';

export type CheckpointStatus = 'pending' | 'checked';

export const ISSUE_STATUS_ORDER: IssueStatus[] = ['pending', 'inProgress', 'resolved', 'closed'];

export const ISSUE_SEVERITY_ORDER: IssueSeverity[] = ['low', 'medium', 'high', 'critical'];

export const ISSUE_CATEGORY_ORDER: IssueCategory[] = ['fire', 'electrical', 'mechanical', 'environment', 'behavior', 'other'];

export function isOpenStatus(status: IssueStatus): boolean {
  return status === 'pending' || status === 'inProgress';
}

export function isClosedStatus(status: IssueStatus): boolean {
  return status === 'resolved' || status === 'closed';
}

// Statuses that count as "open" for the home/summary open-issue counter.
export function isIssueOpen(status: IssueStatus): boolean {
  return isOpenStatus(status);
}

export function nextWorkflowStatus(status: IssueStatus): IssueStatus | null {
  switch (status) {
    case 'pending':
      return 'inProgress';
    case 'inProgress':
      return 'resolved';
    case 'resolved':
      return 'closed';
    default:
      return null;
  }
}

