// Emergency contact domain models.
import { ContactPriority } from './Enums';

export interface Contact {
  id: string;
  name: string;
  role: string;
  phone: string;
  priority: ContactPriority;
  createdAt: number;
}

export interface ContactFormState {
  editingContactId: string;
  name: string;
  role: string;
  phone: string;
  priority: ContactPriority;
}

export function emptyContactForm(): ContactFormState {
  return {
    editingContactId: '',
    name: '',
    role: '',
    phone: '',
    priority: 'primary',
  };
}

export function contactToForm(contact: Contact): ContactFormState {
  return {
    editingContactId: contact.id,
    name: contact.name,
    role: contact.role,
    phone: contact.phone,
    priority: contact.priority,
  };
}

export function normalizePhone(raw: string): string {
  // Strip spaces and dashes for dialing; keep digits, +, * and #.
  let out = '';
  for (let i = 0; i < raw.length; i++) {
    const ch = raw.charAt(i);
    if (ch >= '0' && ch <= '9' || ch === '+' || ch === '*' || ch === '#') {
      out += ch;
    }
  }
  return out;
}

export function isValidPhone(raw: string): boolean {
  const n = normalizePhone(raw);
  return n.length >= 3;
}

