// Clock helper. Centralizes timestamp + dayKey derivation so controllers stay consistent.
// ArkTS runtime Date is allowed (only workflow *scripts* forbid Date.now).

export function nowMs(): number {
  return new Date().getTime();
}

// Returns YYYY-MM-DD in local time for a given ms timestamp.
export function dayKeyOf(ms: number): string {
  const d = new Date(ms);
  const y = d.getFullYear();
  const m = d.getMonth() + 1;
  const day = d.getDate();
  const mm = m < 10 ? `0${m}` : `${m}`;
  const dd = day < 10 ? `0${day}` : `${day}`;
  return `${y}-${mm}-${dd}`;
}

export function todayKey(): string {
  return dayKeyOf(nowMs());
}

// Returns the ms timestamp of the start (00:00) of the day containing `ms`, local time.
export function startOfDayMs(ms: number): number {
  const d = new Date(ms);
  return new Date(d.getFullYear(), d.getMonth(), d.getDate(), 0, 0, 0, 0).getTime();
}

const WEEK_LABELS: string[] = ['日', '一', '二', '三', '四', '五', '六'];

export function weekdayLabel(ms: number): string {
  const d = new Date(ms);
  return `周${WEEK_LABELS[d.getDay()]}`;
}

