// LocalStore: preferences-backed JSON persistence for Pinankou.
//
// Strategy:
// - Durable records (issues, checkpoints, contacts) are serialized to JSON strings
//   in a single @ohos.data.preferences file.
// - The same data is mirrored into AppStorage so @StorageLink components react.
// - Controllers mutate arrays via LocalStore, which re-persists and refreshes AppStorage.
//
// No remote backend. First-run state is empty.

import { preferences } from '@kit.ArkData';
import { common } from '@kit.AbilityKit';
import { Issue } from '../model/Issue';
import { PatrolCheckpoint } from '../model/Patrol';
import { Contact } from '../model/Contact';
import { nowMs } from '../model/Clock';

const PREF_NAME = 'pinankou_store';
const KEY_ISSUES = 'issues';
const KEY_CHECKPOINTS = 'checkpoints';
const KEY_CONTACTS = 'contacts';

// AppStorage reactive keys (consumed by @StorageLink).
export const STORE_ISSUES = 'pinankou_issues';
export const STORE_CHECKPOINTS = 'pinankou_checkpoints';
export const STORE_CONTACTS = 'pinankou_contacts';

type IssueArray = Issue[];
type CheckpointArray = PatrolCheckpoint[];
type ContactArray = Contact[];

export class LocalStore {
  private static instance: LocalStore | null = null;
  private store: preferences.Preferences | null = null;
  private ready: boolean = false;

  static getInstance(): LocalStore {
    if (LocalStore.instance === null) {
      LocalStore.instance = new LocalStore();
    }
    return LocalStore.instance;
  }

  async init(context: common.UIAbilityContext | common.Context): Promise<void> {
    if (this.ready) {
      return;
    }
    this.store = await preferences.getPreferences(context, PREF_NAME);

    const issues = await this.readArray<Issue>(KEY_ISSUES, []);
    const checkpoints = await this.readArray<PatrolCheckpoint>(KEY_CHECKPOINTS, []);
    const contacts = await this.readArray<Contact>(KEY_CONTACTS, []);

    AppStorage.setOrCreate<Issue[]>(STORE_ISSUES, issues);
    AppStorage.setOrCreate<PatrolCheckpoint[]>(STORE_CHECKPOINTS, checkpoints);
    AppStorage.setOrCreate<Contact[]>(STORE_CONTACTS, contacts);
    this.ready = true;
  }

  isReady(): boolean {
    return this.ready;
  }

  getIssues(): Issue[] {
    return AppStorage.get<Issue[]>(STORE_ISSUES) ?? [];
  }

  getCheckpoints(): PatrolCheckpoint[] {
    return AppStorage.get<PatrolCheckpoint[]>(STORE_CHECKPOINTS) ?? [];
  }

  getContacts(): Contact[] {
    return AppStorage.get<Contact[]>(STORE_CONTACTS) ?? [];
  }

  async setIssues(issues: Issue[]): Promise<void> {
    AppStorage.setOrCreate<Issue[]>(STORE_ISSUES, issues);
    await this.writeArray<Issue>(KEY_ISSUES, issues);
  }

  async setCheckpoints(checkpoints: PatrolCheckpoint[]): Promise<void> {
    AppStorage.setOrCreate<PatrolCheckpoint[]>(STORE_CHECKPOINTS, checkpoints);
    await this.writeArray<PatrolCheckpoint>(KEY_CHECKPOINTS, checkpoints);
  }

  async setContacts(contacts: Contact[]): Promise<void> {
    AppStorage.setOrCreate<Contact[]>(STORE_CONTACTS, contacts);
    await this.writeArray<Contact>(KEY_CONTACTS, contacts);
  }

  private async readArray<T>(key: string, fallback: T[]): Promise<T[]> {
    if (this.store === null) {
      return fallback;
    }
    const raw = await this.store.get(key, '');
    if (typeof raw !== 'string' || raw.length === 0) {
      return fallback;
    }
    try {
      const obj: object = JSON.parse(raw);
      if (Array.isArray(obj)) {
        return obj as T[];
      }
      return fallback;
    } catch (e) {
      return fallback;
    }
  }

  private async writeArray<T>(key: string, value: T[]): Promise<void> {
    if (this.store === null) {
      return;
    }
    const raw = JSON.stringify(value);
    await this.store.put(key, raw);
    await this.store.flush();
  }
}

// Collision-resistant id generator. Avoids Math.random in workflow scripts, but this
// is runtime ArkTS where randomness is acceptable; we still seed with time + counter.
let idCounter: number = 0;

export function genId(prefix: string): string {
  idCounter += 1;
  return `${prefix}_${nowMs().toString(36)}_${idCounter.toString(36)}`;
}

