// PatrolController: checkpoint list management + clock-in/check flow.
// A "patrol session" is implicitly active whenever checkpoints exist and are being checked.

import { LocalStore, genId } from '../services/LocalStore';
import { PatrolCheckpoint, CheckpointFormState, emptyCheckpointForm } from '../model/Patrol';
import { CheckpointStatus } from '../model/Enums';
import { nowMs, todayKey, dayKeyOf } from '../model/Clock';

export class PatrolController {
  private store: LocalStore = LocalStore.getInstance();

  list(): PatrolCheckpoint[] {
    return this.store.getCheckpoints().slice();
  }

  getById(id: string): PatrolCheckpoint | null {
    const all = this.store.getCheckpoints();
    for (let i = 0; i < all.length; i++) {
      if (all[i].id === id) {
        return all[i];
      }
    }
    return null;
  }

  beginNote(_id: string): CheckpointFormState {
    const cp = this.getById(_id);
    if (cp === null) {
      return emptyCheckpointForm();
    }
    return { note: cp.note };
  }

  async addCheckpoint(name: string, location: string): Promise<PatrolCheckpoint | null> {
    const trimmed = name.trim();
    if (trimmed.length === 0) {
      return null;
    }
    const all = this.store.getCheckpoints();
    const cp: PatrolCheckpoint = {
      id: genId('cp'),
      name: trimmed,
      location: location.trim(),
      status: 'pending',
      note: '',
      checkedAt: 0,
      dayKey: todayKey(),
    };
    all.push(cp);
    await this.store.setCheckpoints(all);
    return cp;
  }

  async check(id: string, note: string): Promise<void> {
    const all = this.store.getCheckpoints();
    const now = nowMs();
    for (let i = 0; i < all.length; i++) {
      if (all[i].id === id) {
        const prev = all[i];
        all[i] = {
          id: prev.id,
          name: prev.name,
          location: prev.location,
          status: 'checked',
          note: note.trim(),
          checkedAt: now,
          dayKey: dayKeyOf(now),
        } as PatrolCheckpoint;
        await this.store.setCheckpoints(all);
        return;
      }
    }
  }

  async uncheck(id: string): Promise<void> {
    const all = this.store.getCheckpoints();
    for (let i = 0; i < all.length; i++) {
      if (all[i].id === id) {
        const prev = all[i];
        all[i] = {
          id: prev.id,
          name: prev.name,
          location: prev.location,
          status: 'pending',
          note: '',
          checkedAt: 0,
          dayKey: prev.dayKey,
        } as PatrolCheckpoint;
        await this.store.setCheckpoints(all);
        return;
      }
    }
  }

  async remove(id: string): Promise<void> {
    const all = this.store.getCheckpoints();
    const next: PatrolCheckpoint[] = [];
    for (let i = 0; i < all.length; i++) {
      if (all[i].id !== id) {
        next.push(all[i]);
      }
    }
    await this.store.setCheckpoints(next);
  }

  // Checked count / total, e.g. "3 / 8".
  progressText(): string {
    const all = this.store.getCheckpoints();
    let checked = 0;
    for (let i = 0; i < all.length; i++) {
      if (all[i].status === 'checked') {
        checked += 1;
      }
    }
    return `${checked} / ${all.length}`;
  }

  // Checkpoints checked today.
  countCheckedToday(): number {
    const all = this.store.getCheckpoints();
    const today = todayKey();
    let n = 0;
    for (let i = 0; i < all.length; i++) {
      if (all[i].status === 'checked' && all[i].dayKey === today) {
        n += 1;
      }
    }
    return n;
  }

  hasAnyCheckpoint(): boolean {
    return this.store.getCheckpoints().length > 0;
  }
}

