  async uncheck(id: string): Promise<void> {
    const all = this.store.getCheckpoints();
    for (let i = 0; i < all.length; i++) {
      if (all[i].id === id) {
        const prev = all[i];
        all[i] = {
          id: prev.id,
          name: prev.name,
          location: prev.location,
          status: 'pending',
          note: '',
          checkedAt: 0,
          dayKey: prev.dayKey,
        } as PatrolCheckpoint;
        await this.store.setCheckpoints(all);
        return;
      }
    }
  }

  async remove(id: string): Promise<void> {
    const all = this.store.getCheckpoints();
    const next: PatrolCheckpoint[] = [];
    for (let i = 0; i < all.length; i++) {
      if (all[i].id !== id) {
        next.push(all[i]);
      }
    }
    await this.store.setCheckpoints(next);
  }

  // Checked count / total, e.g. "3 / 8".
  progressText(): string {
    const all = this.store.getCheckpoints();
    let checked = 0;
    for (let i = 0; i < all.length; i++) {
      if (all[i].status === 'checked') {
        checked += 1;
      }
    }
    return `${checked} / ${all.length}`;
  }

  // Checkpoints checked today.
  countCheckedToday(): number {
    const all = this.store.getCheckpoints();
    const today = todayKey();
    let n = 0;
    for (let i = 0; i < all.length; i++) {
      if (all[i].status === 'checked' && all[i].dayKey === today) {
        n += 1;
      }
    }
    return n;
  }

  hasAnyCheckpoint(): boolean {
    return this.store.getCheckpoints().length > 0;
  }
}

