// ContactsController: CRUD for emergency contacts + dial action adapter.

import { LocalStore, genId } from '../services/LocalStore';
import { Contact, ContactFormState, emptyContactForm, contactToForm, isValidPhone, normalizePhone } from '../model/Contact';
import { ContactPriority } from '../model/Enums';
import { nowMs } from '../model/Clock';

export interface ContactValidationError {
  field: 'name' | 'phone';
  message: string;
}

export type ContactValidationResult =
  | { ok: true }
  | { ok: false; error: ContactValidationError };

export class ContactsController {
  private store: LocalStore = LocalStore.getInstance();

  list(): Contact[] {
    const priorityRank: Record<string, number> = { 'primary': 0, 'secondary': 1, 'backup': 2 };
    const all = this.store.getContacts().slice();
    all.sort((a: Contact, b: Contact) => {
      const ra = priorityRank[a.priority] ?? 9;
      const rb = priorityRank[b.priority] ?? 9;
      if (ra !== rb) {
        return ra - rb;
      }
      return a.createdAt - b.createdAt;
    });
    return all;
  }

  getById(id: string): Contact | null {
    const all = this.store.getContacts();
    for (let i = 0; i < all.length; i++) {
      if (all[i].id === id) {
        return all[i];
      }
    }
    return null;
  }

  beginCreate(): ContactFormState {
    return emptyContactForm();
  }

  beginEdit(id: string): ContactFormState {
    const c = this.getById(id);
    if (c === null) {
      return emptyContactForm();
    }
    return contactToForm(c);
  }

  validate(form: ContactFormState): ContactValidationResult {
    if (form.name.trim().length === 0) {
      return { ok: false, error: { field: 'name', message: '请填写联系人姓名' } };
    }
    if (!isValidPhone(form.phone)) {
      return { ok: false, error: { field: 'phone', message: '请填写有效电话号码' } };
    }
    return { ok: true };
  }

  async save(form: ContactFormState): Promise<Contact> {
    const name = form.name.trim();
    const role = form.role.trim();
    const phone = normalizePhone(form.phone);
    const all = this.store.getContacts();

    if (form.editingContactId.length > 0) {
      for (let i = 0; i < all.length; i++) {
        if (all[i].id === form.editingContactId) {
          const existing = all[i];
          all[i] = {
            id: existing.id,
            name,
            role,
            phone,
            priority: form.priority as ContactPriority,
            createdAt: existing.createdAt,
          } as Contact;
          await this.store.setContacts(all);
          return all[i];
        }
      }
    }

    const contact: Contact = {
      id: genId('contact'),
      name,
      role,
      phone,
      priority: form.priority as ContactPriority,
      createdAt: nowMs(),
    };
    all.push(contact);
    await this.store.setContacts(all);
    return contact;
  }

  async remove(id: string): Promise<void> {
    const all = this.store.getContacts();
    const next: Contact[] = [];
    for (let i = 0; i < all.length; i++) {
      if (all[i].id !== id) {
        next.push(all[i]);
      }
    }
    await this.store.setContacts(next);
  }

  hasAny(): boolean {
    return this.store.getContacts().length > 0;
  }
}

