// IssuesController: CRUD + status workflow + progress notes for safety issues.
// Mutates LocalStore (persisted) which refreshes AppStorage for reactive UI.

import { LocalStore, genId } from '../services/LocalStore';
import { Issue, IssueFormState, IssueNote, emptyIssueForm, issueToForm } from '../model/Issue';
import {
  IssueStatus,
  IssueSeverity,
  IssueCategory,
  nextWorkflowStatus,
  isIssueOpen,
} from '../model/Enums';
import { nowMs } from '../model/Clock';

export interface IssueValidationError {
  field: 'title';
  message: string;
}

export type IssueValidationResult = { ok: true } | { ok: false; error: IssueValidationError };

export class IssuesController {
  private store: LocalStore = LocalStore.getInstance();

  list(): Issue[] {
    return this.store.getIssues().slice().sort((a: Issue, b: Issue) => b.updatedAt - a.updatedAt);
  }

  getById(id: string): Issue | null {
    const all = this.store.getIssues();
    for (let i = 0; i < all.length; i++) {
      if (all[i].id === id) {
        return all[i];
      }
    }
    return null;
  }

  beginCreate(): IssueFormState {
    return emptyIssueForm();
  }

  beginEdit(id: string): IssueFormState {
    const issue = this.getById(id);
    if (issue === null) {
      return emptyIssueForm();
    }
    return issueToForm(issue);
  }

  validate(form: IssueFormState): IssueValidationResult {
    const title = form.title.trim();
    if (title.length === 0) {
      return { ok: false, error: { field: 'title', message: '请填写事项标题' } };
    }
    return { ok: true };
  }

  async save(form: IssueFormState): Promise<Issue> {
    const title = form.title.trim();
    const description = form.description.trim();
    const location = form.location.trim();
    const assignee = form.assignee.trim();
    const now = nowMs();
    const all = this.store.getIssues();

    if (form.editingIssueId.length > 0) {
      for (let i = 0; i < all.length; i++) {
        if (all[i].id === form.editingIssueId) {
          const existing = all[i];
          all[i] = {
            id: existing.id,
            title,
            description,
            location,
            category: form.category as IssueCategory,
            severity: form.severity as IssueSeverity,
            status: existing.status,
            assignee,
            dueDate: form.dueDate,
            photoUri: form.photoUri,
            createdAt: existing.createdAt,
            updatedAt: now,
            notes: existing.notes,
          } as Issue;
          await this.store.setIssues(all);
          return all[i];
        }
      }
    }

    const issue: Issue = {
      id: genId('issue'),
      title,
      description,
      location,
      category: form.category as IssueCategory,
      severity: form.severity as IssueSeverity,
      status: 'pending',
      assignee,
      dueDate: form.dueDate,
      photoUri: form.photoUri,
      createdAt: now,
      updatedAt: now,
      notes: [],
    };
    all.push(issue);
    await this.store.setIssues(all);
    return issue;
  }

  async setStatus(id: string, status: IssueStatus): Promise<void> {
    const all = this.store.getIssues();
    for (let i = 0; i < all.length; i++) {
      if (all[i].id === id) {
        const prev = all[i];
        all[i] = {
          id: prev.id,
          title: prev.title,
          description: prev.description,
          location: prev.location,
          category: prev.category,
          severity: prev.severity,
          status,
          assignee: prev.assignee,
          dueDate: prev.dueDate,
          photoUri: prev.photoUri,
          createdAt: prev.createdAt,
          updatedAt: nowMs(),
          notes: prev.notes,
        } as Issue;
        await this.store.setIssues(all);
        return;
      }
    }
  }

  // Advance one step along the workflow if possible.
  async advanceStatus(id: string): Promise<IssueStatus | null> {
    const issue = this.getById(id);
    if (issue === null) {
      return null;
    }
    const next = nextWorkflowStatus(issue.status);
    if (next === null) {
      return null;
    }
    await this.setStatus(id, next);
    return next;
  }

  async addNote(id: string, text: string): Promise<IssueNote | null> {
    const trimmed = text.trim();
    if (trimmed.length === 0) {
      return null;
    }
    const all = this.store.getIssues();
    for (let i = 0; i < all.length; i++) {
      if (all[i].id === id) {
        const note: IssueNote = {
          id: genId('note'),
          text: trimmed,
          createdAt: nowMs(),
        };
        const prev = all[i];
        const notes = prev.notes.concat([note]);
        all[i] = {
          id: prev.id,
          title: prev.title,
          description: prev.description,
          location: prev.location,
          category: prev.category,
          severity: prev.severity,
          status: prev.status,
          assignee: prev.assignee,
          dueDate: prev.dueDate,
          photoUri: prev.photoUri,
          createdAt: prev.createdAt,
          updatedAt: note.createdAt,
          notes,
        } as Issue;
        await this.store.setIssues(all);
        return note;
      }
    }
    return null;
  }

  async remove(id: string): Promise<void> {
    const all = this.store.getIssues();
    const next: Issue[] = [];
    for (let i = 0; i < all.length; i++) {
      if (all[i].id !== id) {
        next.push(all[i]);
      }
    }
    await this.store.setIssues(next);
  }

  // Derived counts.
  countOpen(): number {
    const all = this.store.getIssues();
    let n = 0;
    for (let i = 0; i < all.length; i++) {
      if (isIssueOpen(all[i].status)) {
        n += 1;
      }
    }
    return n;
  }

  countOverdue(): number {
    const all = this.store.getIssues();
    const now = nowMs();
    let n = 0;
    for (let i = 0; i < all.length; i++) {
      const it = all[i];
      if (it.dueDate > 0 && it.dueDate < now && isIssueOpen(it.status)) {
        n += 1;
      }
    }
    return n;
  }
}

