// StatsController: derives the Stats board view model from issues + checkpoints.
// Pure derivation over LocalStore reactive state; no persistence.

import { LocalStore } from '../services/LocalStore';
import { Issue } from '../model/Issue';
import { IssueSeverity, isIssueOpen } from '../model/Enums';
import { SeverityCount, TrendPoint, OverdueItem, StatsViewModel } from '../model/Stats';
import { nowMs, dayKeyOf, startOfDayMs, weekdayLabel } from '../model/Clock';

const SEVERITY_ORDER: IssueSeverity[] = ['low', 'medium', 'high', 'critical'];

export class StatsController {
  private store: LocalStore = LocalStore.getInstance();

  build(): StatsViewModel {
    const issues = this.store.getIssues();
    const now = nowMs();

    let openCount = 0;
    let resolvedCount = 0;
    let overdueCount = 0;
    const severityCounts: Record<string, number> = {
      'low': 0,
      'medium': 0,
      'high': 0,
      'critical': 0,
    };
    const overdueItems: OverdueItem[] = [];

    for (let i = 0; i < issues.length; i++) {
      const it = issues[i];
      severityCounts[it.severity] = (severityCounts[it.severity] ?? 0) + 1;

      if (isIssueOpen(it.status)) {
        openCount += 1;
      }
      if (it.status === 'resolved' || it.status === 'closed') {
        resolvedCount += 1;
      }
      if (it.dueDate > 0 && it.dueDate < now && isIssueOpen(it.status)) {
        overdueCount += 1;
        overdueItems.push({
          id: it.id,
          title: it.title,
          severity: it.severity,
          dueDate: it.dueDate,
          assignee: it.assignee,
        });
      }
    }

    const severityDistribution: SeverityCount[] = SEVERITY_ORDER.map((s: IssueSeverity) => {
      return { severity: s, count: severityCounts[s] ?? 0 };
    });

    const weeklyTrend = this.buildWeeklyTrend(issues);

    return {
      openCount,
      resolvedCount,
      overdueCount,
      severityDistribution,
      weeklyTrend,
      overdueItems,
    } as StatsViewModel;
  }

  private buildWeeklyTrend(issues: Issue[]): TrendPoint[] {
    const now = nowMs();
    const todayStart = startOfDayMs(now);
    const points: TrendPoint[] = [];
    const dayMs = 24 * 60 * 60 * 1000;
    // Build 7 buckets oldest -> newest.
    for (let offset = 6; offset >= 0; offset--) {
      const dayStart = todayStart - offset * dayMs;
      const key = dayKeyOf(dayStart);
      points.push({ dayKey: key, label: weekdayLabel(dayStart), count: 0 });
    }
    const indexByKey: Record<string, number> = {};
    for (let i = 0; i < points.length; i++) {
      indexByKey[points[i].dayKey] = i;
    }
    for (let i = 0; i < issues.length; i++) {
      const key = dayKeyOf(issues[i].createdAt);
      const idx = indexByKey[key];
      if (idx !== undefined) {
        points[idx].count += 1;
      }
    }
    return points;
  }
}

