// PhoneAdapter: dial an emergency contact.
// Uses an ACTION_CALL/拨号 want via the ability context. Degrades gracefully:
// if the call cannot be placed, returns false so the caller can show feedback.

import { common, Want } from '@kit.AbilityKit';

export interface CallResult {
  placed: boolean;
  message: string;
}

export class PhoneAdapter {
  static async dial(context: common.UIAbilityContext, phone: string): Promise<CallResult> {
    const number = (phone ?? '').trim();
    if (number.length === 0) {
      return { placed: false, message: '电话号码为空' };
    }
    const want: Want = {
      action: 'ohos.want.action.call',
      parameters: {
        ability.params.stream: [],
      },
      uri: `tel:${number}`,
    } as Want;
    try {
      await context.startAbility(want);
      return { placed: true, message: '正在呼叫' };
    } catch (e) {
      return { placed: false, message: '无法发起呼叫，请检查拨号权限' };
    }
  }
}

