// ActivityController: derives the home recent-activity feed from issues + checkpoints + contacts.
// Pure derivation, newest first, capped.

import { LocalStore } from '../services/LocalStore';
import { Issue } from '../model/Issue';
import { PatrolCheckpoint } from '../model/Patrol';
import { Contact } from '../model/Contact';
import { ActivityItem } from '../model/Activity';
import { isIssueOpen } from '../model/Enums';

const STATUS_LABELS: Record<string, string> = {
  'pending': '待处理',
  'inProgress': '处理中',
  'resolved': '已整改',
  'closed': '已关闭',
};

export class ActivityController {
  private store: LocalStore = LocalStore.getInstance();

  recent(limit: number = 12): ActivityItem[] {
    const items: ActivityItem[] = [];

    const issues = this.store.getIssues();
    for (let i = 0; i < issues.length; i++) {
      const it = issues[i];
      items.push({
        id: `act-issue-created-${it.id}`,
        kind: 'issue-created',
        title: it.title,
        subtitle: `新建事项 · ${STATUS_LABELS[it.status] ?? '待处理'}`,
        createdAt: it.createdAt,
      });
      if (it.updatedAt > it.createdAt && !isIssueOpen(it.status)) {
        items.push({
          id: `act-issue-status-${it.id}`,
          kind: 'issue-status',
          title: it.title,
          subtitle: `状态更新 · ${STATUS_LABELS[it.status] ?? '更新'}`,
          createdAt: it.updatedAt,
        });
      }
    }

    const checkpoints = this.store.getCheckpoints();
    for (let i = 0; i < checkpoints.length; i++) {
      const cp = checkpoints[i];
      if (cp.status === 'checked' && cp.checkedAt > 0) {
        items.push({
          id: `act-patrol-check-${cp.id}`,
          kind: 'patrol-check',
          title: cp.name,
          subtitle: cp.location.length > 0 ? `巡检打卡 · ${cp.location}` : '巡检打卡',
          createdAt: cp.checkedAt,
        });
      }
    }

    const contacts = this.store.getContacts();
    for (let i = 0; i < contacts.length; i++) {
      const c = contacts[i];
      items.push({
        id: `act-contact-added-${c.id}`,
        kind: 'contact-added',
        title: c.name,
        subtitle: c.role.length > 0 ? `新增应急联系人 · ${c.role}` : '新增应急联系人',
        createdAt: c.createdAt,
      });
    }

    items.sort((a: ActivityItem, b: ActivityItem) => b.createdAt - a.createdAt);
    return items.slice(0, limit);
  }
}
